create temporary table game_challenge_seed_rows (
  source_id integer primary key,
  challenge text not null,
  category text not null,
  difficulty integer not null check (difficulty between 1 and 5)
) on commit drop;

values (
  $deck_id$00000000-0000-0000-0000-000000000301$deck_id$,
  $deck_name$Baltimore Link Up Challenges$deck_name$,
  $deck_description$Challenge deck imported from game_challenges_200.csv.$deck_description$,
  true
)
on conflict (id) do update
set
  name = excluded.name,
  description = excluded.description,
  enabled = true,
  updated_at = now();

delete from challenges
where deck_id = $deck_id$00000000-0000-0000-0000-000000000301$deck_id$;

  id,
  deck_id,
  title,
  instructions,
  duration_seconds,
  success_criteria,
  props,
  enabled
)
select
  ($uuid_prefix$00000000-0000-0000-0001-$uuid_prefix$ || lpad((200000 + source_id)::text, 12, $zero$0$zero$))::uuid,
  $deck_id$00000000-0000-0000-0000-000000000301$deck_id$::uuid,
  category,
  challenge,
  case
    when difficulty <= 2 then 30
    when difficulty = 3 then 45
    else 60
  end,
  $success$The host confirms the challenge was attempted.$success$,
  jsonb_build_object(
    $source_id$sourceId$source_id$, source_id,
    $category$category$category$, category,
    $difficulty$difficulty$difficulty$, difficulty
  ),
  true
from game_challenge_seed_rows
order by source_id;

update challenge_decks
set enabled = false, updated_at = now()
where id <> $deck_id$00000000-0000-0000-0000-000000000301$deck_id$;

update challenges
set enabled = false, updated_at = now()
where deck_id is distinct from $deck_id$00000000-0000-0000-0000-000000000301$deck_id$;

update rooms
set
  settings = jsonb_set(
    settings,
    $settings_key_array${selectedChallengeDeckId}$settings_key_array$,
    to_jsonb($deck_id$00000000-0000-0000-0000-000000000301$deck_id$::text),
    true
  ),
  updated_at = now();
